<template>
<div class="user-face-add-container">
  <!-- Header Section -->
  <div class="page-header" v-if="!fromSalary">
    <router-link to="/userFace" class="back-link">
      <svg xmlns="http://www.w3.org/2000/svg" class="icon icon-tabler icon-tabler-chevron-left" width="24" height="24" viewBox="0 0 24 24" stroke-width="2.5" stroke="#007BFF" fill="none" stroke-linecap="round" stroke-linejoin="round">
        <path stroke="none" d="M0 0h24v24H0z" fill="none"/>
        <polyline points="15 6 9 12 15 18" />
      </svg>
      <h4 class="page-title">{{$t('Add_worker')}}</h4>
    </router-link>
  </div>

  <div class="row mt-4">
    <div class="col-8">
      <div class="form-card">
        <div class="form-group">
          <label class="form-label m-0">{{$t('fio')}} <span class="required">*</span></label>
          <mdb-input class="modern-input m-0 p-0 mt-1" v-model="name" @input="handleNameInput" size="md" outline group type="text" validate error="wrong" success="right"/>
          <small class="invalid-text" v-if="$v.name.$dirty && !$v.name.required">
            {{$t('name_invalid_text')}}
          </small>
        </div>
        <div class="form-row">
          <div class="form-group col-md-6">
            <label class="form-label">IWMS XODIMLAR (ID) SI</label>
            <input 
              type="text" 
              class="modern-input-field" 
              v-model="id" 
              @input="handleIdInput"
              @keypress="onlyNumbers"
              placeholder="Faqat raqamlar"
            />
          </div>
          <div class="form-group col-md-6">
            <label class="form-label m-0" style="margin-bottom: 7px !important;">{{$t('born_date')}}</label>
            <mdb-input class="modern-input m-0 p-0" v-model="born_date" @input="SearchClientNamePass($event)" size="md" outline group type="date" validate error="wrong" success="right"/>
          </div>
        </div>
        <div class="form-group">
          <label class="form-label m-0">{{$t('picture')}}</label>
          <div class="image-upload-section mt-0">
            <div class="image-preview-container">
              <div class="image-preview" v-show="!PicShow && image">
                <img :src="hostname + image" class="preview-image" alt="Preview">
                <button @click="delImage" class="delete-image-btn" type="button">
                  <svg xmlns="http://www.w3.org/2000/svg" class="icon icon-tabler icon-tabler-x" width="20" height="20" viewBox="0 0 24 24" stroke-width="2.5" stroke="#fff" fill="none">
                    <path stroke="none" d="M0 0h24v24H0z" fill="none"/>
                    <line x1="18" y1="6" x2="6" y2="18" />
                    <line x1="6" y1="6" x2="18" y2="18" />
                  </svg>
                </button>
              </div>
              <div class="image-preview" v-show="!PicShow && image2">
                <img :src="hostname + image2" class="preview-image" alt="Preview 2">
              </div>
              <div class="image-preview" v-if="photo_url">
                <img :src="hostname + photo_url" class="preview-image" alt="Photo">
              </div>
            </div>
            <input hidden id="inputFileToLoad" @change="previewFile()" accept="image/png, image/gif, image/jpeg" type="file" ref="file_Img" />
            <div class="upload-buttons">
              <input type="file" style="display: none;" id="file_download" @change="onFileChange" accept="image/*" />
              <label for="file_download" class="upload-btn upload-btn-primary">
                <svg xmlns="http://www.w3.org/2000/svg" class="icon icon-tabler icon-tabler-upload" width="18" height="18" viewBox="0 0 24 24" stroke-width="2" stroke="currentColor" fill="none">
                  <path stroke="none" d="M0 0h24v24H0z" fill="none"/>
                  <path d="M4 17v2a2 2 0 0 0 2 2h12a2 2 0 0 0 2 -2v-2" />
                  <polyline points="7 9 12 4 17 9" />
                  <line x1="12" y1="4" x2="12" y2="16" />
                </svg>
                <span>Rasm yuklash</span>
              </label>
              <label @click="showPhoto = true" class="upload-btn upload-btn-secondary">
                <svg xmlns="http://www.w3.org/2000/svg" class="icon icon-tabler icon-tabler-camera" width="18" height="18" viewBox="0 0 24 24" stroke-width="2" stroke="currentColor" fill="none">
                  <path stroke="none" d="M0 0h24v24H0z" fill="none"/>
                  <path d="M5 7h1a2 2 0 0 0 2 -2a1 1 0 0 1 1 -1h6a1 1 0 0 1 1 1a2 2 0 0 0 2 2h1a2 2 0 0 1 2 2v9a2 2 0 0 1 -2 2h-14a2 2 0 0 1 -2 -2v-9a2 2 0 0 1 2 -2" />
                  <circle cx="12" cy="13" r="3" />
                </svg>
                <span>{{$t('photo')}}</span>
              </label>
            </div>
          </div>
        </div>
        <div class="form-row ">
          <div class="form-group col-md-6">
            <label class="form-label">{{$t('smena')}}</label>
            <erpSelect
              :options="get_smena_list.rows"
              @select="selectOption"
              :selected="smena_name"
              searchKey="smena_nomi"
              :label="$t('smena')"
            />
          </div>
          <div class="form-group col-md-6">
            <label class="form-label">Зарплата</label>
            <erpSelect
              :options="get_salary_list.rows"
              @select="selectOptionSalary"
              :selected="oylik_name"
              searchKey="name"
              :label="$t('salary')"
            />
          </div>
        </div>

        <div class="form-row">
          <div class="form-group col-md-6">
            <label class="form-label">{{$t('phone_number')}}</label>
            <input type="text" class="modern-input-field" v-mask="'+998 (##) ###-##-##'" placeholder="+998 (__) ___-__-__" @input="SearchClientNamePass(phone_number)" v-model="phone_number" />
          </div>
          <div class="form-group col-md-6">
            <label class="form-label">{{$t('passport_number')}}</label>
            <input
              id="passport"
              v-mask="'AA#######'"
              v-model="passport_number"
              placeholder="AA1234567"
              class="modern-input-field"
              @input="SearchClientNamePass(passport_number)"
            />
          </div>
        </div>

        <div class="form-row">
          <div class="form-group col-md-6">
            <label class="form-label m-0">{{$t('address')}}</label>
            <mdb-input class="modern-input m-0 p-0 mt-1" v-model="address" size="md" outline group type="text" validate error="wrong" success="right"/>
          </div>
          <div class="form-group col-md-6">
            <label class="form-label">{{$t('dept')}}</label>
            <erpSelect
              :options="get_dept_list.rows"
              @select="selectOptionDept"
              :selected="dept_name"
              searchKey="deptname"
              :label="$t('dept')"
            />
          </div>
        </div>

        <div class="form-group">
          <label class="form-label m-0">{{$t('note')}}</label>
          <mdb-input class="modern-input m-0 p-0 mt-1" v-model="note" @input="SearchClientNote($event)" size="md" outline group type="textarea" validate error="wrong" success="right"/>
        </div>

        <div class="form-group">
          <div class="checkbox-wrapper">
            <input
              v-model="oshibka"
              type="checkbox"
              id="oshibka"
              class="modern-checkbox"
            />
            <label for="oshibka" class="checkbox-label text-danger">{{$t('oshibka')}}</label>
          </div>
        </div>

        <!-- Action Buttons -->
        <div class="form-actions">
          <mdb-btn color="success" @click="save_data" class="submit-btn">
            <mdb-icon icon="check" class="mr-2" />
            {{$t('add')}}
          </mdb-btn>
        </div>
          
          <webcam  v-if="showPhoto" @getPhotosub="takePhoto"/>
        <Toast ref="message"></Toast>
      </div>
    </div>
    <div class="col-4">
      <div class="user-list-card" v-show="id==0">
        <div class="user-list-header">
          <h5 class="user-list-title">Xodimlar ro'yxati</h5>
        </div>
        <div class="user-list-body">
          <div v-for="(item,i) in client_list.rows" :key="i" class="user-item" 
            @click="getBemorId(i,item)" :class="{'activeUser' : active_bemor == i }">
            <div class="user-avatar">
              <img src="../../assets/client.png" alt="User">
            </div>
            <div class="user-info">
              <p class="user-name">{{item.ism}}</p>
              <p class="user-details">
                <span>Год: {{item.born_date}}</span>
                <span>Тел: {{item.phone_number}}</span>
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>
  
</template>

<script>
import erpSelect from "../../components/erpSelectDynamic.vue";
import {mdbRow, mdbCol, mdbInput, mdbBtn, mdbIcon} from 'mdbvue'
import { required } from 'vuelidate/lib/validators'
import webcam from '../webcam/webcam_Add.vue'
import {mapActions,mapGetters} from 'vuex'
export default {
  components:{
    mdbRow, mdbCol, mdbInput, mdbBtn, mdbIcon, webcam,
    erpSelect
  },
  props: {
    fromSalary: {
      type: Boolean,
      default: false
    }
  },
  validations: {
      name: {required},
      // phone_number: {required},
      // passport_number: {required},
      // district_name : {required},
      // clientgroup_name : {required},
    },
  data() {
    return {
      hostname: this.$store.state.server_ip,
      name: '',
      id: this.fromSalary ? '' : this.$route.params.id,
      phone_number: '',
      passport_number: '',
      client_group_name: '',
      client_group_id:null,
      born_date: '',
      address: '',
      note: '',
      active_bemor:'',
      showPhoto: false,
      photo_url: '',
      loading: false,
      client_id : null,
      client_data : {},

      PicShow: true,
      base64: '',
      image: '',
      image2: '',
      client_list: {
        rows:[]
      },

      oshibka: false,
      auth_user_updator_id: 0,

      dept_name: '',
      dept_id: 0,
      smena_name: '',
      smena_id: 0,
      oylik_name: '',
      oulik_id: 0,
      res_badgenumber:0,
      without_gr_id: 0,
      nameTimeout: null,
    }
  },
  // props:{
  //   client_id: {
  //     type: Number,
  //     default: null,
  //   }
  // },
   computed: mapGetters(['all_district_t', 'all_client_controler', 'allWorker', 'get_dept_list', 'get_smena_list', 'get_salary_list']),
  async mounted(){
      await this.fetch_Dept();
      await this.fetch_Smena();
      await this.fetch_Salary();
      // await this.fetch_user();
      this.client_list = this.allWorker;
      this.active_bemor = -1;
      console.log('this.get_salary_list', this.get_salary_list)
      if(this.get_salary_list.rows.length>0)
      {
        this.oylik_name = this.get_salary_list.rows[0].name;
        this.oylik_id = this.get_salary_list.rows[0].id;
        this.res_badgenumber = this.get_salary_list.rows[0].id;
        this.without_gr_id = this.get_salary_list.rows[0].reserved_value;
      }
    },
  async created()
  {
    // Agar fromSalary prop true bo'lsa, id ni 0 qilish (modal ochilganda)
    if (this.fromSalary) {
      this.id = '';
    }
    
    // Agar id 0 bo'lsa, bo'sh qilamiz
    if (this.id === 0 || this.id === '0') {
      this.id = '';
    }
    
    if(this.id > 0 || (this.id && this.id !== '' && this.id !== 0))
    {
      const res = await fetch(this.$store.state.hostname + '/SkudMyUserinfoes/' + this.id);
      const data = await res.json();
      console.log('data')
      console.log(data)
      this.name = data.ism;
      this.phone_number = data.phone_number;
      this.passport_number = data.passport;
      this.born_date = data.born_date;
      this.address = data.address;
      this.res_badgenumber = data.res_badgenumber;
      this.without_gr_id = data.without_gr_id;
      this.photo_url = data.image_url;
      this.note = data.group_name;
      if(data.departid){
        this.dept_id = data.departid;
        this.dept_name = data.familiya;
      }
      if(data.group_id){
        this.smena_id = data.group_id;
        this.smena_name = data.group_name;
      }
      if(data.auth_user_updator_id == 0){
        this.oshibka = true;
      }
      else{
        this.oshibka = false;
      }
    }

  },
  methods: {
    ...mapActions([ 'fetch_user', 'fetch_Dept', 'fetch_Smena', 'fetch_Salary']),
    delImage(){
      this.base64 = ''
      this.PicShow = true
      this.image = ''
    },
    selectOption(option){
      this.smena_name = option.smena_nomi;
      this.smena_id = option.id;
    },

    selectOptionDept(option){
      this.dept_name = option.deptname;
      this.dept_id = option.deptid;
    },
    selectOptionSalary(option){
      console.log(option);
      this.oylik_name = option.name;
      this.oylik_id = option.id;
      this.res_badgenumber = option.id;
      this.without_gr_id = option.reserved_value;
    },
    handleIdInput(event) {
      // Faqat raqamlarni qoldiramiz
      let value = event.target.value.replace(/\D/g, '');
      
      // Agar qiymat 0 bo'lsa yoki bo'sh bo'lsa, bo'sh qilamiz
      if (value === '0' || value === 0 || value === '') {
        value = '';
        this.id = '';
      } else {
        // Number'ga o'tkazamiz (agar kerak bo'lsa)
        this.id = parseInt(value) || '';
      }
      
      event.target.value = value;
    },
    onlyNumbers(event) {
      // Faqat raqamlar va Backspace, Delete, Tab, Escape, Enter, Arrow keys ruxsat beriladi
      const char = String.fromCharCode(event.which);
      if (!/[0-9]/.test(char) && !/[0-9]/.test(event.key)) {
        event.preventDefault();
      }
    },
    async previewFile(){
      const preview = document.getElementById('prewImageClientAdd');
        const file = document.querySelector('input[type=file]').files[0];
        this.PicShow = true;
      var reader = new FileReader();
      reader.addEventListener("load", function () {
        this.image =  reader.result;
        preview.src = reader.result;
      }, true);
      if (file) {
          this.PicShow = false
        reader.readAsDataURL(file);
      }
    },
    takePhoto(img){
      console.log(img)
      this.photo_url = img;
      this.showPhoto = false;
    },
    MountedFunc(){
      this.id = '';
      this.clv_ws();
      this.active_bemor = -1;
    },
    getBemorId(i, data){
      console.log('getBemorId data:', data)
      this.client_data = data;
      this.active_bemor = i;
      
      // Ismni to'ldirish (fio yoki ism)
      this.name = data.fio || data.ism || '';
      
      // Agar id 0 bo'lsa, bo'sh qilamiz
      this.id = (data.userid && data.userid !== 0) ? data.userid : '';
      
      // Telefon raqami
      this.phone_number = data.phone_number || '';
      
      // Passport raqami
      this.passport_number = data.passport || data.passport_number || '';
      
      // Manzil
      this.address = data.adddress || data.address || '';

      this.photo_url = data.image_url || '';
      this.dept_id = data.departid || '';
      this.dept_name = data.familiya || data.dept_name || '';
      this.smena_id = data.group_id || '';
      this.smena_name = data.group_name || data.smena_name || '';
      this.res_badgenumber = data.res_badgenumber || '';
      this.without_gr_id = data.without_gr_id || '';
      
      
      // Eslatma
      this.note = data.note || '';
      
      
      // Tug'ilgan sana
      this.born_date = data.addiotionala_information || data.born_date || '';
      
      // Client group
      if(data.group){
        this.client_group_name = data.group.name;
        this.client_group_id = data.group.id;
      }
      
      // Passport rasm
      if(!data.passport_image_url || data.passport_image_url == ''){
        this.base64 = ''
        this.PicShow = true;
        this.image = ''
      }else{
        this.PicShow = false;
      }
      
      // Preview image elementini topish (agar mavjud bo'lsa)
      this.$nextTick(() => {
        let preview = document.getElementById('prewImageClientAdd');
        if(preview && data.passport_image_base_64){
          preview.src = data.passport_image_base_64;
        }
        
        // Photo URL
        this.photo_url = data.image_url || '';
        
        // Departament
        if(data.departid){
          this.dept_id = data.departid;
          this.dept_name = data.familiya || data.dept_name || '';
        }
        
        // Smena (group)
        if(data.group_id){
          this.smena_id = data.group_id;
          this.smena_name = data.group_name || data.smena_name || '';
        }
        
        // Res badgenumber
        if(data.res_badgenumber){
          this.res_badgenumber = data.res_badgenumber;
        }
        
        // Without gr id
        if(data.without_gr_id){
          this.without_gr_id = data.without_gr_id;
        }
      });
    },
    clv_ws(){
      this.name = '';
      this.id = '';
      this.phone_number = '';
      this.passport_number = '';
      this.address = '';
      this.note = '';
      this.base64 = '';
      this.born_date = '';
      this.client_group_name = '';
      this.client_group_id = null,
      this.image = '';
      this.image2 = '';
      this.photo_url = '';
      this.showPhoto = false;
      this.PicShow = true;
      let preview = document.getElementById('prewImageClientAdd');
      if(preview){
        preview.src = '';
      }

    },

    next_data(){
      this.id = '';
      this.$emit('close_data', this.client_data)
    },


    save_data :  async function(){
      let url = '/SkudMyUserinfoes';
        if(this.$route.params.id != 0){
          url = '/SkudMyUserinfoes/updateUserInfo'
        }
      if(this.oshibka == false){
        this.auth_user_updator_id = 1;
      }
      else{
        this.auth_user_updator_id = 0;
      }
      console.log('this.base64')
      
      // console.log(this.base64)
      if(this.$v.$invalid)
      {
        this.$v.$touch();
        this.$refs.message.warning('please_fill')
        return false;
      }
      const requestOptions = {
        method : "POST",
        headers: { "Content-Type" : "application/json" },
        body: JSON.stringify({
          "ism" : this.name,
          "userid" : (this.id === '' || this.id === 0) ? 0 : parseInt(this.id) || 0,
          "badgenumber" : (this.id === '' || this.id === 0) ? 0 : parseInt(this.id) || 0,
          "departid": this.dept_id,
          "familiya": this.dept_name,
          "group_id": this.smena_id,
          "group_name": this.smena_name,
          "image_url": this.photo_url,
          "middle_name" : this.note,
          "gr": this.auth_user_updator_id,
          "res_badgenumber": this.res_badgenumber,
          "without_gr_id" : this.without_gr_id,
          "address" : this.address,
          "passport" : this.passport_number,
          "phone_number": this.phone_number,
          "born_date": this.born_date,
          
          
        })
      };
      try{
        this.loading = true;
        const response = await fetch(this.$store.state.hostname + url, requestOptions);
        console.log(response)
        this.loading = false;
        if(response.status == 201 || response.status == 200)
        {
        console.log('dasdas')
          const tryjson = await response.json();
          console.log(tryjson)
          if (this.fromSalary) {
            // user_salary sahifasidan modal orqali chaqirilgan bo'lsa
            this.$refs.message.success('Added_successfully')
            this.$emit('added', tryjson);
          } else {
            this.$router.push('/userFace')
            this.clv_ws();
            this.$refs.message.success('Added_successfully')
          }
          // console.log('fire' + i)
        }
        else{
          const data = await response.text();
          this.modal_info = data;
          this.modal_status = true;
          
        }
      }
      catch{
        this.loading = false;
        this.modal_info = this.$i18n.t('network_ne_connect'); 
        this.modal_status = true;
      }
    },

    handleNameInput(event) {
      // mdb-input dan kelgan eventni to'g'ri qayta ishlash
      const value = event && event.target ? event.target.value : (event || this.name);
      this.name = value;
      // Debounce bilan SearchClientNamePass ni chaqirish
      if (this.nameTimeout) {
        clearTimeout(this.nameTimeout);
      }
      this.nameTimeout = setTimeout(() => {
        this.SearchClientNamePass(value);
      }, 300);
    },
    async SearchClientNamePass(search){
      console.log('search')
      console.log(search)
      if(search == ''){
      await this.fetch_user();
      this.client_list = this.allWorker;
        return
      }
      // /TegirmonClient/getPaginationSearchByFioOrPassportSerailNumberOrHomeOrMobilePhoneNumber?page=0&size=100&fio_or_serial_number=
      try{
        // this.loading = true;
        const response = await fetch(this.$store.state.hostname + "/SkudMyUserinfoes/getPaginationSearchByIsmOrPassportSerailNumberOrMobilePhoneNumberFaceUser?page=0&size=100&fio_or_serial_number=" + search);
        const data = await response.json();
        console.log('weqeqw')
        console.log(data)
        // this.loading = false;
        if(response.status == 201 || response.status == 200)
        {
          this.client_list.rows = data.items_list;
          if(data.items_list == 0){
            // this.$refs.message.error('not_client')
          }
          // this.$refs.message.success('Added_successfully')
          return true;
        }
        else{
          // const data = await response.text();
          this.modal_info = data;
          this.modal_status = true;
          return false;
        }
      }
      catch{
        // this.loading = false;
        this.client_list = this.allWorker;
        this.modal_info = this.$i18n.t('network_ne_connect');
        this.modal_status = true;
      }
      
    },
    async SearchClientNote(search){
      console.log('search')
      console.log(search)
      if(search == ''){
      await this.fetch_user();
      this.client_list = this.allWorker;
        return
      }
      // /TegirmonClient/getPaginationSearchByFioOrPassportSerailNumberOrHomeOrMobilePhoneNumber?page=0&size=100&fio_or_serial_number=
      try{
        // this.loading = true;
        const response = await fetch(this.$store.state.hostname + "/TegirmonWorker/getPaginationByNote?page=0&size=100&note_str=" + search);
        const data = await response.json();
        console.log('weqeqw')
        console.log(data)
        // this.loading = false;
        if(response.status == 201 || response.status == 200)
        {
          this.client_list.rows = data.items_list;
          if(data.items_list == 0){
            // this.$refs.message.error('not_client')
          }
          // this.$refs.message.success('Added_successfully')
          return true;
        }
        else{
          // const data = await response.text();
          this.modal_info = data;
