      async onFileChange(event) {
        const file = event.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = e => {
        this.fetchBase64ToHttpImg(e.target.result);
          this.imageBase64 = e.target.result;
        };
        reader.readAsDataURL(file);
